noncompliant:
// Noncompliant: Types defined outside of named namespace
public class Foo  // Noncompliant
{
    public void DoSomething() { }
}

public struct Bar  // Noncompliant
{
    public int Value;
}

public enum Status  // Noncompliant
{
    Active,
    Inactive
}

compliant:
// Compliant: Types defined within a named namespace
namespace MyCompany.MyProject
{
    public class Foo
    {
        public void DoSomething() { }
    }

    public struct Bar
    {
        public int Value;
    }

    public enum Status
    {
        Active,
        Inactive
    }
}
